export const indiaStats = {
  total: indiaEarthquakes.length,
  avgMagnitude: (indiaEarthquakes.reduce((s, e) => s + e.magnitude, 0) / indiaEarthquakes.length).toFixed(1),
  maxMagnitude: Math.max(...indiaEarthquakes.map(e => e.magnitude)),
  byState: indiaEarthquakes.reduce((acc, e) => { acc[e.state] = (acc[e.state] || 0) + 1; return acc; }, {} as Record<string, number>),
  byRegion: indiaEarthquakes.reduce((acc, e) => { acc[e.region] = (acc[e.region] || 0) + 1; return acc; }, {} as Record<string, number>),
  byDecade: indiaEarthquakes.reduce((acc, e) => { const decade = Math.floor(new Date(e.time).getFullYear() / 10) * 10; acc[`${decade}s`] = (acc[`${decade}s`] || 0) + 1; return acc; }, {} as Record<string, number>),
};

export const recentIndiaEarthquakes = indiaEarthquakes
  .filter(e => !e.isHistorical)
  .sort((a, b) => new Date(b.time).getTime() - new Date(a.time).getTime());

export const historicalIndiaEarthquakes = indiaEarthquakes
  .filter(e => e.isHistorical)
  .sort((a, b) => new Date(b.time).getTime() - new Date(a.time).getTime());
